import { useState, useEffect } from 'react';
import axiosInstance from '../axiosConfig';
import { useAuth } from '../context/AuthContext';
import { Link } from 'react-router-dom';

const Home = () => {
  const { user } = useAuth();
  const [tours, setTours] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchTours = async () => {
      try {
        const response = await axiosInstance.get('/api/tours');
        setTours(response.data);
        setLoading(false);
      } catch (error) {
        console.error('抓取失敗', error);
        setLoading(false);
      }
    };
    fetchTours();
  }, []);

  return (
    <div className="bg-gray-100 min-h-screen">
      {/* 手機容器 */}
      <div className="max-w-[420px] mx-auto bg-white min-h-screen shadow-2xl flex flex-col">

        {/* Top Profile Header (參考你截圖的頂部) */}
        <div className="p-6 flex justify-between items-center bg-white">
          <div>
            <p className="text-gray-400 text-xs">Good morning!</p>
            <h2 className="font-bold text-lg text-gray-800">
              Admin ({user?.username || 'Guest'})
            </h2>
          </div>
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-indigo-100 rounded-full overflow-hidden border-2 border-white shadow-sm">
                <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Felix" alt="avatar" />
            </div>
            <button className="relative p-1">
              <span className="text-2xl">🔔</span>
              <span className="absolute top-0 right-0 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
            </button>
          </div>
        </div>

        {/* Order List Stats (中間那塊統計) */}
        <div className="px-6 mb-6">
          <div className="bg-white border border-gray-100 p-4 rounded-2xl shadow-sm flex items-center space-x-4">
            <div className="bg-yellow-50 p-3 rounded-xl">
               <span className="text-2xl">📋</span>
            </div>
            <div>
              <p className="text-gray-400 text-xs font-medium">Order List</p>
              <p className="text-xl font-black text-gray-800">{tours.length}</p>
            </div>
          </div>
        </div>

        {/* View Package Section */}
        <div className="px-6 flex-1">
          <h3 className="font-bold text-gray-800 mb-4">View Package</h3>

          <div className="space-y-6">
            {loading ? <p>Loading...</p> : tours.map((tour) => (
              <div key={tour._id} className="flex space-x-4 group">
                {/* 圖片區 */}
                <div className="w-32 h-32 flex-shrink-0 rounded-3xl overflow-hidden shadow-md">
                   {tour.imageUrl ? (
                     <img src={tour.imageUrl} alt={tour.title} className="w-full h-full object-cover" />
                   ) : (
                     <div className="w-full h-full bg-indigo-50 flex items-center justify-center text-3xl">🏝️</div>
                   )}
                </div>

                {/* 文字與價格 */}
                <div className="flex flex-col justify-between py-1">
                  <div>
                    <h4 className="font-bold text-gray-800 leading-tight">{tour.title}</h4>
                    <p className="text-gray-400 text-xs mt-1 uppercase tracking-wider">{tour.location || 'Australia'}</p>
                  </div>

                  <div>
                    <span className={`inline-block px-4 py-1.5 rounded-lg font-bold text-sm shadow-sm ${tour.status === 'Available' ? 'bg-green-400 text-white' : 'bg-red-500 text-white'}`}>
                      {tour.status === 'Available' ? `AUD ${tour.price}` : 'SOLD OUT'}
                    </span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Bottom Button */}
        <div className="p-6 sticky bottom-0 bg-white bg-opacity-90 backdrop-blur-sm">
          <Link 
            to="/manage-tours" 
            className="block w-full bg-emerald-500 text-white text-center font-bold py-4 rounded-2xl shadow-lg shadow-emerald-100 active:scale-95 transition"
          >
            Add Tour Package
          </Link>
        </div>

        {/* 手機底部黑條模擬 */}
        <div className="h-6 flex justify-center items-center pb-2">
           <div className="w-32 h-1 bg-gray-200 rounded-full"></div>
        </div>
      </div>
    </div>
  );
};

export default Home;
